#[test]
fn rfonts_cs_slot_preserved_for_complex_script_embed_form() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:cs="Times New Roman"/><w:rtl/></w:rPr><w:t>English العربية</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:cs="Times New Roman""#),
        "ECMA-376 §17.3.2.26 / §17.8.3.6 / §17.8.3.10: the Complex Script slot is one of the four \
         independent font slots; the serializer must re-emit w:cs so the rtl run stays linked to its \
         CS (embedded) font form. Missing in reserialized XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §17.3.2.26: rFonts with ascii+cs on an rtl run is conformant; round-trip must open without repair",
    );
}

#[test]
fn rfonts_hint_attribute_roundtrips_verbatim() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Arial" w:hAnsi="Arial" w:eastAsia="MS Gothic" w:hint="eastAsia"/></w:rPr><w:t>省略…</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:hint="eastAsia""#),
        "ECMA-376 §17.3.2.26 / §17.18.41: hint is authored run content selecting the slot for \
         ambiguous glyphs; Word preserves it on save, so the serializer must re-emit it verbatim and \
         not silently drop it. Missing in reserialized XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §17.3.2.26 / §17.18.41: hint=\"eastAsia\" is a valid ST_Hint value; round-trip must open without repair",
    );
}

#[test]
fn empty_rfonts_inherits_and_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts/></w:rPr><w:t>Ellipsis…</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ECMA-376 §17.3.2.26: a slotless <w:rFonts/> is conformant (Word writes/reads it as pure inheritance); round-trip must open without repair",
    );
    let got = accept_text(&b);
    assert_eq!(
        got.trim(),
        "Ellipsis…",
        "ECMA-376 §17.3.2.26 / §17.8.3.10: an empty rFonts only affects font-slot inheritance, never \
         the character content; the accepted read text must equal the literal run text"
    );
}

