#[test]
fn rfonts_overlength_name_not_truncated_on_save() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="AbcdefghijklmnopqrstuvwxyzABCDEFGH" w:hAnsi="AbcdefghijklmnopqrstuvwxyzABCDEFGH"/></w:rPr><w:t>over</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.88 / §2.1.270: an over-length rFonts name is conformant markup Word opens \
         (the <32 cap is a render/consumption limit, not a save rewrite); round-trip must validate with no errors",
    );
    let got = accept_text(&b);
    assert_eq!(
        got.trim(),
        "over",
        "MS-OI29500 §2.1.88 / §2.1.270 / ECMA-376 §17.3.2.26: the font-name length limit governs glyph \
         selection at render, not text content; the accepted read view returns the run text unchanged"
    );
}

