#[test]
fn all_five_rfonts_slots_plus_hint_roundtrip_together() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:hint="default" w:ascii="Calibri" w:hAnsi="Calibri" w:eastAsia="MS Mincho" w:cs="Arial"/></w:rPr><w:t>multiscript</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex: w:ascii="Calibri"[^>]*w:hAnsi="Calibri"[^>]*w:eastAsia="MS Mincho"[^>]*w:cs="Arial"
    // No `regex` crate is available in dev-dependencies, so this is translated to
    // an ordered substring check: find each slot in document order within the
    // serialized text. This preserves the regex's intent (all four literal slots
    // present, in this order) while staying buildable.
    let ascii = xml.find(r#"w:ascii="Calibri""#);
    let hansi = ascii.and_then(|i| xml[i..].find(r#"w:hAnsi="Calibri""#).map(|j| i + j));
    let ea = hansi.and_then(|i| xml[i..].find(r#"w:eastAsia="MS Mincho""#).map(|j| i + j));
    let cs = ea.and_then(|i| xml[i..].find(r#"w:cs="Arial""#).map(|j| i + j));
    assert!(
        cs.is_some(),
        "ECMA-376 §17.3.2.26 / §17.8.3.6 / schema CT_Fonts: all four literal slots \
         (ascii, hAnsi, eastAsia, cs) must survive together and in document order so each script \
         class keeps its embedded-font linkage; none may be dropped on reserialize. \
         (regex translated to ordered substring check.) XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §17.3.2.26 / schema CT_Fonts: all four name slots plus a valid hint is schema-valid; round-trip must open without repair",
    );
}

#[test]
fn cs_slot_with_bcs_toggle_roundtrips_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Arial" w:hAnsi="Arial" w:cs="Arial"/><w:bCs/></w:rPr><w:t>complex script run</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:cs="Arial""#),
        "ECMA-376 §17.3.2.26 / CT_Fonts: the complex-script font slot must be re-emitted so the run \
         stays linked to its complex-script embedded form; stemma must not silently drop the cs slot \
         it parsed. Missing in XML: {xml}"
    );
    assert!(
        xml.contains("<w:bCs/>"),
        "ECMA-376 §17.3.2.2: bCs is the complex-script bold toggle that selects embedBold/\
         embedBoldItalic for complex-script text; it must survive reserialize unchanged. Missing in XML: {xml}"
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §17.3.2.26 / §17.3.2.2 / §17.3.2.7 / schema CT_Fonts: an rFonts with a cs slot plus bCs is schema-conformant; round-trip must open without repair",
    );
}

